head.script:
scwin.onpageload = function() {
	scwin.f_FieldClear();
    let blNo = JSON.parse($p.getPopupParam()).blno || JSON.parse($p.getPopupParam()).pBlno;
    ed_oldBlno.setValue(blNo);
    $c.data.setPopupTitle("House B/L No Change");
};

// as-is과 동일하게 스크립트 생성
scwin.f_PopUp = function (disGubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {

    var rtnList = new Array();
    switch (disGubun){
		case "oldCustomer" :		//거래처 팝업(Search Shipper)
            udc_oldCustomer.ilCommonPopUp(udc_oldCustomer_callBackFunc,  
                                    ed_oldCustCd.getValue().trim(),  
                                    ed_oldCustNm.getValue(), 
                                    pWinCloseTF,
                                    '6',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
									'Customer',                      // Title순서	                                                           
									'140,300',                      // 보여주는 각 컬럼들의 폭	                                               
									null,                           // 컬럼중에서 숨기는	컬럼 지정	                                       
									null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
									'500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
									'500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
									null,                           // 윈도우 위치 Y좌표	                                                   
									null,                           // 윈도우 위치 X좌표                                                       
									null,                           // 중복체크여부	("F")                                                      
									pAllSearchTF,                   // 전체검색허용여부	("F")                                                  
									null,                            // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")  
									pNoDataCloseTF);
            break;										
		case "newCustomer" :		//거래처 팝업(Search Shipper)
            udc_newCustomer.ilCommonPopUp(udc_newCustomer_callBackFunc, 
                                    ed_newCustCd.getValue().trim(),  
                                    ed_newCustNm.getValue(), 
                                    pWinCloseTF,
                                    '6',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
									'Customer',                      // Title순서	                                                           
									'140,300',                      // 보여주는 각 컬럼들의 폭	                                               
									null,                           // 컬럼중에서 숨기는	컬럼 지정	                                       
									null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
									'500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
									'500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
									null,                           // 윈도우 위치 Y좌표	                                                   
									null,                           // 윈도우 위치 X좌표                                                       
									null,                           // 중복체크여부	("F")                                                      
									pAllSearchTF,                   // 전체검색허용여부	("F")                                                  
									null,                            // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")  
									pNoDataCloseTF);
            break;	
		default:
  	break;	
    }
};

scwin.udc_oldCustomer_callBackFunc = function (ref) {
    if (ref != null) {
        ed_oldCustCd.setValue(ref[0]); 
        ed_oldCustNm.setValue(ref[1]);
    }
};

scwin.udc_newCustomer_callBackFunc = function (ref) {
    if (ref != null) {
        ed_newCustCd.setValue(ref[0]); 
        ed_newCustNm.setValue(ref[1]);
    }
};

scwin.udc_oldCustomer_onclickEvent = function (e) {
    scwin.f_PopUp("oldCustomer","T","F","F");
};

scwin.udc_newCustomer_onclickEvent = function (e) {
    scwin.f_PopUp("newCustomer","T","F","F");	
};

scwin.f_FieldClear = function () {
    // 포커스 이동
    ed_newBlno.focus();
};

scwin.f_WinClose = function (e) {

    var arrRtnVal = [];

    arrRtnVal[0] = "N/A";
    arrRtnVal[1] = ed_newBlno.getValue();

    // WebSquare 팝업 반환
    $c.win.closePopup(arrRtnVal);
};

scwin.btn_close_onclick = function (e) {
    scwin.f_WinClose();
};


scwin.ed_newBlno_onkeyup = function (e) {
    ed_newBlno.setValue(e.target.value.toUpperCase())
};
